<div class="space-y-6" x-data="menuAdminForm(@js($initial))"><x-admin.section-card title="Menu Settings" description="Use a unique location to connect this menu to a storefront area."><div class="grid gap-5 md:grid-cols-2"><label class="admin-label">Name<input class="admin-input" name="name" value="{{ old('name',$menu->name) }}" required></label><label class="admin-label">Slug<input class="admin-input" name="slug" value="{{ old('slug',$menu->slug) }}" required></label><label class="admin-label">Location<select class="admin-input" name="location"><option value="">No automatic location</option>@foreach(['header-primary','footer-shop','footer-sports','footer-support','footer-company','homepage-categories','homepage-sports'] as $location)<option value="{{ $location }}" @selected(old('location',$menu->location)===$location)>{{ $location }}</option>@endforeach</select></label><label class="flex items-center gap-3 rounded-2xl border border-slate-200 p-4"><input type="hidden" name="is_active" value="0"><input type="checkbox" name="is_active" value="1" @checked(old('is_active',$menu->is_active ?? true))><span class="font-bold">Active menu</span></label></div></x-admin.section-card>
<x-admin.section-card title="Menu Items" description="Create a multi-level Imprint-style navigation hierarchy. A child can reference any row above or below it by parent selection."><div class="space-y-4"><template x-for="(item,index) in items" :key="item.key"><div class="rounded-2xl border border-slate-200 p-4"><input type="hidden" :name="`items[${index}][key]`" x-model="item.key"><div class="grid gap-3 md:grid-cols-2 xl:grid-cols-4"><label class="admin-label">Label<input class="admin-input" :name="`items[${index}][label]`" x-model="item.label" required></label><label class="admin-label">Parent<select class="admin-input" :name="`items[${index}][parent_key]`" x-model="item.parent_key"><option value="">Root item</option><template x-for="candidate in items.filter(candidate => candidate.key !== item.key)" :key="candidate.key"><option :value="candidate.key" x-text="candidate.label || 'Untitled item'"></option></template></select></label><label class="admin-label">Link type<select class="admin-input" :name="`items[${index}][link_type]`" x-model="item.link_type"><option value="category">Category</option><option value="route">Named route</option><option value="custom">Custom URL</option></select></label><label class="admin-label" x-show="item.link_type==='category'">Category<select class="admin-input" :name="`items[${index}][category_id]`" x-model="item.category_id"><option value="">Select category</option>@foreach($categories as $category)<option value="{{ $category->id }}">{{ $category->indented_name }}</option>@endforeach</select></label><label class="admin-label" x-show="item.link_type==='route'">Route name<input class="admin-input" :name="`items[${index}][route_name]`" x-model="item.route_name" placeholder="categories.index"></label><label class="admin-label xl:col-span-2" x-show="item.link_type==='custom'">Custom URL<input class="admin-input" :name="`items[${index}][url]`" x-model="item.url" placeholder="/quote-request or https://..."></label><label class="admin-label">Target<select class="admin-input" :name="`items[${index}][target]`" x-model="item.target"><option value="_self">Same tab</option><option value="_blank">New tab</option></select></label><label class="admin-label">Sort order<input class="admin-input" type="number" min="0" :name="`items[${index}][sort_order]`" x-model="item.sort_order"></label><label class="admin-label">CSS class<input class="admin-input" :name="`items[${index}][css_class]`" x-model="item.css_class"></label></div><div class="mt-3 flex items-center justify-between"><label class="flex items-center gap-2 text-sm font-bold"><input type="hidden" :name="`items[${index}][is_active]`" value="0"><input type="checkbox" :name="`items[${index}][is_active]`" value="1" x-model="item.is_active"> Active</label><div class="flex gap-2"><button type="button" class="btn btn-white" x-on:click="move(index,-1)" :disabled="index===0">↑</button><button type="button" class="btn btn-white" x-on:click="move(index,1)" :disabled="index===items.length-1">↓</button><button type="button" class="btn btn-white text-red-700" x-on:click="remove(index)">Remove</button></div></div></div></template><button type="button" class="btn btn-white" x-on:click="addItem()">+ Add Menu Item</button></div></x-admin.section-card><div class="sticky bottom-4 z-30 flex justify-end gap-3 rounded-2xl border border-slate-200 bg-white/95 p-4 shadow-soft backdrop-blur"><a class="btn btn-white" href="{{ route('admin.menus.index') }}">Cancel</a><button class="btn btn-red">{{ $isEdit ? 'Update Menu' : 'Create Menu' }}</button></div></div>
@once<script>function menuAdminForm(initial){return{items:initial||[],addItem(){this.items.push({key:`item-new-${Date.now()}-${Math.random()}`,parent_key:'',label:'',link_type:'category',category_id:'',route_name:'',url:'',target:'_self',css_class:'',is_active:true,sort_order:this.items.length})},remove(index){const key=this.items[index].key;this.items.forEach(item=>{if(item.parent_key===key)item.parent_key=''});this.items.splice(index,1)},move(index,direction){const target=index+direction;if(target<0||target>=this.items.length)return;[this.items[index],this.items[target]]=[this.items[target],this.items[index]];this.items.forEach((item,i)=>item.sort_order=i)}}}</script>@endonce
